```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/include/llvm/Analysis/ScalarEvolution.h
@@
   class SCEVCallbackVH final : public CallbackVH {
     ScalarEvolution *SE = nullptr;

   public:
     SCEVCallbackVH(Value *V, ScalarEvolution *SE = nullptr);
@@
     friend class SCEVCallbackVH;
@@
-      DenseMap<SCEVCallbackVH, const SCEV *, DenseMapInfo<Value *>>;
+      DenseMap<SCEVCallbackVH, const SCEV *, DenseMapInfo<SCEVCallbackVH>>;
     // This maps Values to their most refined SCEV.
     DenseMap<Value *, const SCEV *> RewriteMap;
@@
   };
+
+} // end namespace llvm
+
+// Provide DenseMapInfo for llvm::ScalarEvolution::SCEVCallbackVH to prevent
+// constructing CallbackVH on DenseMap's sentinel pointer values.
+namespace llvm {
+
+template <> struct DenseMapInfo<ScalarEvolution::SCEVCallbackVH> {
+  using KeyT = ScalarEvolution::SCEVCallbackVH;
+  using SEPtr = ScalarEvolution *;
+
+  // Use special SE pointer tags to distinguish empty/tombstone while keeping
+  // the underlying Value* as nullptr so CallbackVH does not register handles.
+  static inline KeyT getEmptyKey() {
+    return KeyT(nullptr, reinterpret_cast<SEPtr>(-1));
+  }
+  static inline KeyT getTombstoneKey() {
+    return KeyT(nullptr, reinterpret_cast<SEPtr>(-2));
+  }
+  static unsigned getHashValue(const KeyT &Key) {
+    // Hash only the underlying Value* for normal keys. For sentinels (Value* ==
+    // nullptr) use the SE tag to make them distinct.
+    Value *V = const_cast<KeyT &>(Key).operator Value *();
+    if (!V)
+      return DenseMapInfo<SEPtr>::getHashValue(Key.SE);
+    return DenseMapInfo<Value *>::getHashValue(V);
+  }
+  static bool isEqual(const KeyT &LHS, const KeyT &RHS) {
+    // Equal if both wrap the same Value*. If both are nullptr (sentinel forms),
+    // compare the SE tag to distinguish empty vs tombstone.
+    Value *LV = const_cast<KeyT &>(LHS).operator Value *();
+    Value *RV = const_cast<KeyT &>(RHS).operator Value *();
+    if (!LV && !RV)
+      return LHS.SE == RHS.SE;
+    return LV == RV;
+  }
+};
